function parseOrdenNota(nota) {
  if(!nota) return {notas:"",contacto:"",fechaEntrega:"",iva:false};
  try { return typeof nota==="string" ? JSON.parse(nota) : nota; } catch(e) { return {notas:nota||"",contacto:"",fechaEntrega:"",iva:false}; }
}

function exportCSV(sales) {
  const header = ["Folio","Fecha","Hora","Cliente","Canal","Metodo Pago","Cajero","Subtotal","Descuentos","Total","Estado"];
  const rows = sales.map(s => [
    s.folio, fmtDate(s.fecha), fmtTime(s.fecha), s.cliente,
    CANAL_MAP[s.canal]?.label||s.canal,
    PAGO_MAP[s.metodo_pago]?.label||s.metodo_pago,
    s.cajero||"",
    Number(s.subtotal).toFixed(2), Number(s.descuento_total).toFixed(2), Number(s.total).toFixed(2),
    s.cancelada?"Cancelada":s.devolucion?"Devolucion":"Activa"
  ]);
  const csv = [header,...rows].map(r=>r.map(v=>`"${v}"`).join(",")).join("\n");
  const blob = new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8"});
  const a=document.createElement("a"); a.href=URL.createObjectURL(blob);
  a.download=`ventas_${new Date().toISOString().slice(0,10)}.csv`; a.click();
}

